export interface IconProps extends Omit<SVGProps<SVGSVGElement>, 'name'> {
  /** Which design-system glyph to render. */
  name: IconName
  /** Square pixel size of the rendered glyph. Defaults to 24. */
  size?: number
}

/**
 * Renders a single design-system icon. Color follows `currentColor`
 * (set it with a Tailwind `text-*` class on this element or an ancestor).
 */
export function Icon({ name, size = 24, className, ...rest }: IconProps) {
  const def = icons[name]
  return (
    <svg
      width={size}
      height={size}
      viewBox={def.viewBox}
      fill="none"
      xmlns="http://www.w3.org/2000/svg"
      className={className}
      aria-hidden={rest['aria-label'] ? undefined : true}
      role={rest['aria-label'] ? 'img' : undefined}
      {...rest}
    >
      {def.body}
    </svg>
  )
}

/** Sorted list of every available icon name (handy for galleries/search). */
export const iconNames = Object.keys(icons).sort() as IconName[]
